import { useState, useEffect } from 'react'
import { motion, AnimatePresence } from 'framer-motion'
import { Menu, X, Phone } from 'lucide-react'
import { CalendlyBtn } from '@/components/ui/calendly-btn'
import { nav, phone } from '@/content/site'

export default function Nav() {
  const [open, setOpen] = useState(false)
  const [scrolled, setScrolled] = useState(false)

  useEffect(() => {
    const onScroll = () => setScrolled(window.scrollY > 20)
    window.addEventListener('scroll', onScroll, { passive: true })
    return () => window.removeEventListener('scroll', onScroll)
  }, [])

  const linkClass = scrolled
    ? 'text-sm text-slate-600 hover:text-slate-900 transition-colors'
    : 'text-sm text-slate-300 hover:text-white transition-colors'

  const phoneClass = scrolled
    ? 'flex items-center gap-1.5 text-sm text-slate-500 hover:text-slate-700 transition-colors'
    : 'flex items-center gap-1.5 text-sm text-slate-400 hover:text-white transition-colors'

  return (
    <motion.header
      initial={{ y: -20, opacity: 0 }}
      animate={{ y: 0, opacity: 1 }}
      transition={{ duration: 0.6 }}
      className={`fixed top-0 left-0 right-0 z-50 transition-all duration-300 ${
        scrolled ? 'bg-white/95 backdrop-blur-md shadow-sm' : 'bg-transparent'
      }`}
    >
      <nav className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
        <div className="flex justify-between items-center h-16">
          <a href="#" className="flex items-center">
            <img
              src={`${import.meta.env.BASE_URL}dp_nelson_logo.webp`}
              alt="Douglas P Nelson"
              className="h-10 w-auto"
            />
          </a>

          {/* Desktop */}
          <div className="hidden md:flex items-center gap-8">
            {nav.links.map((link) => (
              <a key={link.label} href={link.href} className={linkClass}>
                {link.label}
              </a>
            ))}
          </div>

          <div className="hidden md:flex items-center gap-3">
            <a href={`tel:${phone}`} className={phoneClass}>
              <Phone size={14} />
              {phone}
            </a>
            <CalendlyBtn
              size="sm"
              className="bg-blue-600 hover:bg-blue-700 text-white border-transparent"
            >
              {nav.cta}
            </CalendlyBtn>
          </div>

          {/* Mobile toggle */}
          <button
            className={`md:hidden p-2 transition-colors ${scrolled ? 'text-slate-700' : 'text-slate-300'}`}
            onClick={() => setOpen(!open)}
            aria-label="Toggle menu"
          >
            {open ? <X size={22} /> : <Menu size={22} />}
          </button>
        </div>
      </nav>

      {/* Mobile menu */}
      <AnimatePresence>
        {open && (
          <motion.div
            initial={{ opacity: 0, height: 0 }}
            animate={{ opacity: 1, height: 'auto' }}
            exit={{ opacity: 0, height: 0 }}
            className="md:hidden bg-white/98 backdrop-blur-md border-t border-slate-200 overflow-hidden shadow-lg"
          >
            <div className="px-4 py-4 flex flex-col gap-4">
              {nav.links.map((link) => (
                <a
                  key={link.label}
                  href={link.href}
                  className="text-slate-700 hover:text-blue-600 text-sm py-1 transition-colors"
                  onClick={() => setOpen(false)}
                >
                  {link.label}
                </a>
              ))}
              <a href={`tel:${phone}`} className="flex items-center gap-2 text-sm text-slate-500">
                <Phone size={14} />
                {phone}
              </a>
              <div onClick={() => setOpen(false)}>
                <CalendlyBtn
                  size="sm"
                  className="bg-blue-600 hover:bg-blue-700 text-white border-transparent w-fit"
                >
                  {nav.cta}
                </CalendlyBtn>
              </div>
            </div>
          </motion.div>
        )}
      </AnimatePresence>
    </motion.header>
  )
}
